<template>
    <div>
      <v-form class="form-login" v-if="isLogged===false">
        <p>Username</p>
        <v-text-field type="text" v-model="username" ></v-text-field>
        <p>password</p>
        <v-text-field type="password" v-model="password" ></v-text-field>
        <button @click.prevent="login">Login</button>
      </v-form>

      <v-card v-if="isLogged===true">
          <v-card-title>
              <div class="px-2">
                  List Reagents
              </div>
              <v-spacer class="m-2"></v-spacer>
              <v-text-field
                  v-model="search"
                  append-icon="mdi-magnify"
                  label="Search"
                  single-line
                  hide-details
              ></v-text-field>
              <v-spacer class="m-2"></v-spacer>
              <div class="px-2">
                  <v-btn
                  color="primary"
                  dark
                  class="mt-2"
                  @click="dialogOpenCreate"
                  >
                      New Reagent
                  </v-btn>
              </div>
          </v-card-title>

          <!-- for dialog (modal) create and also use as edit dialog -->
          <v-dialog
            v-model="dialog"
            max-width="500px"
          >
            <v-card>
              <v-card-title>
                <span class="text-h5 mb-3">{{formTitle}}</span>
              </v-card-title>

              <v-card-text>
                <v-container>
                  <v-row>
                    <v-col
                      cols="12"
                    >
                      <v-text-field
                        v-model="editedReagent.name"
                        label="Reagent's Name"
                      ></v-text-field>
                    </v-col>
                    <v-col
                      cols="12"
                      sm="6"
                    >
                      <v-text-field
                        v-model="editedReagent.lot"
                        label="No. Lot"
                      ></v-text-field>
                    </v-col>
                    <v-col
                      cols="12"
                      sm="6"
                    >
                      <v-text-field
                        v-model="editedReagent.quantity"
                        label="Quantity"
                      ></v-text-field>
                    </v-col>
                    <v-col
                      cols="12"
                      sm="6"
                    >
                      <v-text-field
                        v-model="editedReagent.size"
                        label="Size"
                      ></v-text-field>
                    </v-col>
                    <v-col
                      cols="12"
                      sm="6"
                    >
                      <v-text-field
                        v-model="editedReagent.stock"
                        label="Stock"
                      ></v-text-field>
                    </v-col>
                    <v-col
                      cols="12"
                      sm="6"
                    >
                      <span>Received date</span>
                      <v-text-field
                        @keyup="changeRecDate"
                        :value="editedReagent.rec_date"
                        label="Format: mmddyy or -"
                      ></v-text-field>
                    </v-col>
                    <v-col
                      cols="12"
                      sm="6"
                    >
                      <span>Expired Date</span>
                      <v-text-field
                        @keyup="changeExpDate"
                        :value="editedReagent.exp_date"
                        label="Format: mmddyy or -"
                      ></v-text-field>
                    </v-col>
                  </v-row>
                </v-container>
              </v-card-text>

              <v-card-actions>
                <v-spacer></v-spacer>
                <v-btn
                  color="blue darken-1"
                  text
                  @click="dialogClose"
                >
                  Cancel
                </v-btn>
                <v-btn
                  color="blue darken-1"
                  text
                  @click="storeData"
                >
                  Save
                </v-btn>
              </v-card-actions>
            </v-card>
          </v-dialog>
          <!-- End of dialog (modal) create and also use as edit dialog -->

          <!-- Delete dialog -->
          <v-dialog v-model="dialogDelete" max-width="500px">
            <v-card>
              <v-card-title class="text-h5">
                Are you sure you want to delete this item?<br>
                <table class="dialog_delete">
                  <tr><td>Reagent</td><td> : {{editedReagent.name}}</td></tr>
                  <tr><td>Lot</td><td> : {{editedReagent.lot}}</td></tr>
                  <tr><td>Received date</td><td> : {{editedReagent.rec_date}}</td></tr>
                  <tr><td>Expired date</td><td> : {{editedReagent.exp_date}}</td></tr>
                </table>
              </v-card-title>
              <v-card-actions>
                <v-spacer></v-spacer>
                <v-btn color="blue darken-1" text @click="dialogClose">Cancel</v-btn>
                <v-btn color="blue darken-1" text @click="deleteReagentConfirm">OK</v-btn>
                <v-spacer></v-spacer>
              </v-card-actions>
            </v-card>
          </v-dialog>
          <!-- End of dialog delete -->

          <v-data-table
              :headers="headers"
              :items="showReagents"
              :search="search"
              :sort-by.sync="sortName"
              :sort-desc.sync="sortDesc"
          >
              <template v-slot:[`item.exp_in`]="{item}">
                  <v-chip color="red" v-if="item.exp_in=='EXPIRED'"><b>EXPIRED</b></v-chip>
                  <span v-else>{{item.exp_in}}</span>
              </template>

              <template v-slot:[`item.actions`]="{ item }">
                  <v-icon
                      small
                      class="mr-2"
                      @click="dialogOpenEdit(item)"
                  >
                      mdi-pencil
                  </v-icon>
                  <v-icon
                      small
                      @click="dialogOpenDelete(item)"
                  >
                      mdi-delete
                  </v-icon>
              </template>
          
          </v-data-table>
      </v-card>
    </div>
</template>

<script>
import {nanoid} from 'nanoid';
import axios from 'axios';
const apiToken = "asfdhajhHJHjjfs89459825/.,525;2';S&&*(^^&&^H3QWYWRFUHFSD";
const apiRoute = "https://list-reagent.herokuapp.com/reagent-png";

export default {
    async mounted(){
      
      // get data from database;
      await axios.get(apiRoute,{
            headers:{
              'api-token': `${apiToken}`,
            }
          }).then(res=>{
            if (res.data.reagent==='') {
              this.data_reagents = [];
            }else{
              this.data_reagents = JSON.parse(res.data.reagent)
            }
          }).catch(err=>console.log(err))

    },
    data(){
        return{
            isLogged: false,
            username: '',
            password: '',

            sortName: "name",
            sortDesc: false,

            dialog: false, //state for open or close dialog (create & edit)
            dialogCreate: false, //state if dialog is for create
            dialogEdit: false, //state if dialog is for edit

            dialogDelete: false,
            search: "",
            headers:[
                {
                    text: "Reagent's Name",
                    // align: 'start',
                    value: 'name',
                },
                { text: 'No. Lot', value: 'lot' },
                { text: 'Quantity', value: 'quantity' },
                { text: 'size', value: 'size' },
                { text: 'stock', value: 'stock' },
                { text: 'Received Date', value: 'rec_date' },
                { text: 'Expired Date', value: 'exp_date' },
                { text: 'Expired in', value: 'exp_in' },
                { text: 'Actions', value: 'actions', sortable: false },
            ],
            data_reagents: [],
            editedReagent:{
                    "id"        : "",
                    "name"      : "",
                    "lot"       : "",
                    "quantity"  : "",
                    "size"      : "",
                    "stock"     : "",
                    "rec_date"  : "",
                    "exp_date"  : ""
            },
            defaultReagent:{
                    "id"        : "",
                    "name"      : "",
                    "lot"       : "",
                    "quantity"  : "",
                    "size"      : "",
                    "stock"     : "",
                    "rec_date"  : "",
                    "exp_date"  : ""
            },
        }
    },
    computed:{
        // to process data_reagents with display format 
        showReagents(){
            let reagent = [];
            this.data_reagents.forEach(v=>{
                let objReagent = Object.assign({}, v);
                objReagent.exp_in = this.calcExpired(v.exp_date)
                objReagent.rec_date = this.convertDate(v.rec_date);
                objReagent.exp_date = this.convertDate(v.exp_date);
                reagent.push(objReagent)
            });
            return reagent;
        },
        // to change form title in dialog create and edit
        formTitle(){
          return this.dialogCreate && !this.dialogEdit ? "Add New Reagent" : "Edit Reagent"
        }
    },
    methods:{
        //method for login and to unlock the page
        login(){
          if (this.username==='afast' && this.password==='Hello World!!!') {
            this.isLogged = true;
          }
        },
        convertDate(date){
            // convert "070821" (mmddyy format) to "2021-07-08 VII/08/21"
            if (date=='-') {
              return `(${date})`;
            }
            const m = `${date[0]}${date[1]}`;
            const d = `${date[2]}${date[3]}`;
            const y = `20${date[4]}${date[5]}`;

            const dateTime = new Date(y, m-1, d);
            const year = dateTime.getFullYear() ;
            const month = (`0${dateTime.getMonth()+1}`).slice(-2);
            const day = ("0"+dateTime.getDate()).slice(-2);

            const arrRomawi = ['null','I','II','III','IV','V','VI','VII','VIII','IX','X','XI','XII'];
            return `${year}-${month}-${day} , ${arrRomawi[parseInt(month)]}/${day}/${year}`
        },
        calcExpired(date){
            if (date=='-') {
              return `(${date}) atau 5 tahun setelah dibuka`;
            }
            const m = `${date[0]}${date[1]}`;
            const d = `${date[2]}${date[3]}`;
            const y = `20${date[4]}${date[5]}`;

            let exp_date = new Date( y, m-1, d).getTime()/1000;// in seconds
            let now_date = new Date().getTime()/1000;// in seconds

            let exp_in = Math.floor( (exp_date-now_date)/60/60/24 ); // result in days
            return exp_in <=0 ? "EXPIRED" : exp_in+" Days";
        },
        dialogOpenCreate(){
            this.dialog = true; // open modal dialog
            this.dialogCreate = true; // to know this is a create state
            this.editedReagent = Object.assign({},this.defaultReagent);
        },
        dialogOpenEdit(item){
            // data_reagents is the first data object before computed process
            let reagent = this.data_reagents.filter(v=>{
              return v.id === item.id
            })[0]
            this.dialog = true; // open modal dialog
            this.dialogEdit = true; // to know this is an edit state
            this.editedReagent = Object.assign({},reagent);
        },
        dialogOpenDelete(item){
            this.dialogDelete = true;
            this.editedReagent = Object.assign({},item);
        },
        dialogClose(){
            this.editedReagent = Object.assign({},this.defaultReagent);
            this.dialog = this.dialogCreate = this.dialogEdit = this.dialogDelete = false;
        },
        // for handle rec date input
        changeRecDate(e){
            let value = e.target.value;
            if(value=='-'){
              e.target.value = value;
              this.editedReagent.rec_date = value;
              return;
            }
            this.editedReagent.rec_date = value.replace(/\D/g, '');
            if(this.editedReagent.rec_date.length>6){
                this.editedReagent.rec_date = this.editedReagent.rec_date.substr(0,6);
            }
            e.target.value = this.editedReagent.rec_date
        },
        // for handle exp date input
        changeExpDate(e){
            let value = e.target.value;
            if(value=='-'){
                e.target.value = value;
                this.editedReagent.exp_date = value;
                return;
              }
            this.editedReagent.exp_date = value.replace(/\D/g, '');
            if(this.editedReagent.exp_date.length>6){
                this.editedReagent.exp_date = this.editedReagent.exp_date.substr(0,6);
            }
            e.target.value = this.editedReagent.exp_date
        },
        // Add new Reagent or edit reagent
        async storeData(){
            const {id, name, lot, quantity, size, stock, rec_date, exp_date} = this.editedReagent;
            const dataForm = Object.assign({}, this.editedReagent);

            //if in edit state, id not created
            dataForm.id = this.dialogEdit===true ? id : nanoid();
            let isValid = true;

            if( name=='' || lot=='' || (quantity/1)*1!=quantity || quantity=='' 
                || size=='' || (stock/1)!=stock || stock=='' || (rec_date.length<6 && rec_date!='-') 
                || (exp_date.length<6 && exp_date!='-') ){
                    isValid=false;
            }
            dataForm.quantity = parseInt(dataForm.quantity);
            dataForm.stock = parseInt(dataForm.stock);

            if(isValid){
                // process edit
                if(this.dialogEdit==true && this.dialogCreate==false){
                  this.data_reagents = this.data_reagents.map(v=>{
                    return v.id===dataForm.id ? dataForm : v ;
                  })
                }
                // process create
                if(this.dialogEdit==false && this.dialogCreate==true){
                  this.data_reagents.unshift(dataForm);
                }
                
                // store updated data to backend
                await this.sendToBackend();

                this.dialogClose();
            }
            else{
              alert('Input Data Tidak Sesuai')
            }
        },
        // for delete reagent
        async deleteReagentConfirm(){
          this.data_reagents = this.data_reagents.filter(v=>{
            return v.id !== this.editedReagent.id
          });
          // store updated data to backend
          await this.sendToBackend();

          this.dialogClose()
        },
        async sendToBackend(){
          let result = await axios.post(apiRoute,{data_reagent: JSON.stringify(this.data_reagents)},{
            headers:{
              'api-token': `${apiToken}`
            }
          })

          if (result.status===200) {
            return
          }
          else{
            return alert('koneksi ke database gagal, cek koneksi internet');
          }
        }
    }
}
</script>

<style>
    .form-login{
      position: absolute;
      left: 50%;
      top: 50%;
      transform: translate(-50%,-50%);
      width:350px;
      height: 290px;
      border:1px solid black;
      padding: 15px;
    }

    .form-login button{
      position: absolute;
      bottom: 20px;
      left:50%;
      transform: translateX(-50%);
      background: navy;
      color:white;
      padding: 7px 25px;
    }

    .v-dialog .col-12 > div:first-child, .v-dialog .col-12{
        padding-top: 0px !important ;
        padding-bottom: 0px ;
    }
    .v-dialog .col-12 span{
        position: relative !important;
        top: 8px !important;
    }
    table.dialog_delete td{
      font-weight: normal !important;
      font-size: 12px !important;
    }
</style>